def merge_within(pairs):
    if not pairs:
        return []

    merged = [sorted(pairs[0])]

    for start, end in pairs[1:]:
        last_start, last_end = merged[-1]

        if start - last_end <= 2:
            merged[-1][1] = max(last_end, end)
        else:
            merged.append([start, end])

    return sorted(merged, key=lambda x: x[0])
